#!/usr/bin/env node
/**
 * Copy Product Docs
 *
 * Copies hand-authored product documentation from docs-site/docs/ into
 * docs-generated/docs/ so it is served by the same docs plugin instance
 * as the generated Architecture content (ADRs + specs). The destination
 * is wiped and re-copied on every build -- author product docs ONLY in
 * docs-site/docs/, never in docs-generated/.
 *
 * Sidebar: sidebars.ts exposes `docsSidebar` as an autogenerated sidebar
 * over the `docs` directory; use _category_.json files per section
 * folder to control labels and ordering. See docs-site/CONTENT-PLAN.md.
 */

const fs = require('fs');
const path = require('path');

const DOCS_SOURCE = path.join(__dirname, '../docs');
const DOCS_DEST = path.join(__dirname, '../../docs-generated/docs');

function main() {
  console.log('Copying product docs...');

  if (fs.existsSync(DOCS_DEST)) {
    fs.rmSync(DOCS_DEST, { recursive: true });
  }

  if (!fs.existsSync(DOCS_SOURCE)) {
    console.log('  No docs-site/docs directory found, skipping product docs copy');
    return;
  }

  fs.cpSync(DOCS_SOURCE, DOCS_DEST, { recursive: true });

  const count = fs.readdirSync(DOCS_DEST, { recursive: true }).length;
  console.log(`  Copied product docs (${count} entries)`);
}

main();
